import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Chip,
  Stack,
  Alert,
  Snackbar,
  CircularProgress,
  LinearProgress,
  useTheme,
  FormControlLabel,
  Switch,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  FormHelperText,
  Checkbox
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon,
  ContentCopy as ContentCopyIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { getRules, createRule, updateRule, deleteRule, getNodeGroups, createNodeGroup, updateNodeGroup, deleteNodeGroup } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Rules = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [rules, setRules] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedRule, setSelectedRule] = useState(null);
  const [editRule, setEditRule] = useState({
    name: '',
    type: '',
    includePatterns: [],
    excludePatterns: [],
    useAllNodes: true,
    mode: 'select', // 'select' or 'urltest'
    nodeList: [],
    selectedNodes: [] // 当手动选择模式时使用的已选节点列表
  });
  const [nodeGroups, setNodeGroups] = useState([]);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [rulesData, groupsData] = await Promise.all([
        getRules(),
        getNodeGroups()
      ]);
      setRules(rulesData);
      setNodeGroups(groupsData);
      setError(null);
    } catch (err) {
      setError(err.response?.data?.error || '获取数据失败');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (rule = null) => {
    if (rule) {
      setSelectedRule(rule);
      setEditRule({
        ...rule,
        includePatterns: rule.includePatterns || [],
        excludePatterns: rule.excludePatterns || [],
        useAllNodes: rule.useAllNodes ?? true,
        mode: rule.mode || 'select',
        selectedNodes: rule.selectedNodes || []
      });
    } else {
      setSelectedRule(null);
      setEditRule({
        name: '',
        type: '',
        includePatterns: [],
        excludePatterns: [],
        useAllNodes: true,
        mode: 'select',
        nodeList: [],
        selectedNodes: []
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedRule(null);
    setEditRule({
      name: '',
      type: '',
      includePatterns: [],
      excludePatterns: [],
      useAllNodes: true,
      mode: 'select',
      nodeList: [],
      selectedNodes: []
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      if (selectedRule) {
        await updateRule(selectedRule.id, editRule);
      } else {
        await createRule(editRule);
      }
      await fetchData();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError('Failed to save rule');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteRule(id);
      await fetchData();
      setSuccess(true);
    } catch (err) {
      setError('Failed to delete rule');
    } finally {
      setLoading(false);
    }
  };

  const handleCopy = (rule) => {
    const newRule = { ...rule, name: `${rule.name} (Copy)` };
    handleOpenDialog(newRule);
  };

  const handleSaveGroup = async () => {
    try {
      setLoading(true);
      if (selectedGroup) {
        await updateNodeGroup(selectedGroup.id, editGroup);
      } else {
        await createNodeGroup(editGroup);
      }
      await fetchData();
      setSuccess(true);
      handleCloseGroupDialog();
    } catch (err) {
      setError(err.response?.data?.error || '保存分组失败');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteGroup = async (id) => {
    try {
      setLoading(true);
      await deleteNodeGroup(id);
      await fetchData();
      setSuccess(true);
    } catch (err) {
      setError(err.response?.data?.error || '删除分组失败');
    } finally {
      setLoading(false);
    }
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                规则管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={styles.iconButton}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Box sx={{ mb: 2, display: 'flex', justifyContent: 'flex-end', gap: 1 }}>
        <Button
          variant="contained"
          size="small"
          startIcon={<AddIcon />}
          onClick={() => handleOpenDialog()}
          sx={styles.actionButton}
        >
          添加规则
        </Button>
      </Box>

      <motion.div
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <Grid container spacing={1.5}>
          {rules.map((rule) => (
            <Grid item xs={12} sm={6} lg={4} key={rule.id}>
              <motion.div variants={cardVariants}>
                <Card sx={styles.card}>
                  <CardContent>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                      <Typography variant="h6">{rule.name}</Typography>
                      <Stack direction="row" spacing={0.5}>
                        <IconButton 
                          size="small" 
                          onClick={() => handleCopy(rule)}
                          sx={{
                            color: 'text.secondary',
                            '&:hover': {
                              color: 'primary.main',
                              backgroundColor: 'action.hover',
                            },
                          }}
                        >
                          <ContentCopyIcon fontSize="small" />
                        </IconButton>
                        <IconButton 
                          size="small" 
                          onClick={() => handleOpenDialog(rule)}
                          sx={{
                            color: 'text.secondary',
                            '&:hover': {
                              color: 'primary.main',
                              backgroundColor: 'action.hover',
                            },
                          }}
                        >
                          <EditIcon fontSize="small" />
                        </IconButton>
                        <IconButton 
                          size="small" 
                          onClick={() => handleDelete(rule.id)}
                          sx={{
                            color: 'text.secondary',
                            '&:hover': {
                              color: 'error.main',
                              backgroundColor: 'action.hover',
                            },
                          }}
                        >
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      </Stack>
                    </Box>
                    <Stack direction="row" spacing={1} sx={{ mb: 1.5 }}>
                      <Chip 
                        label={rule.type} 
                        size="small"
                        sx={styles.chip.primary}
                      />
                      <Chip 
                        label={rule.mode === 'select' ? "手动选择" : "自动测速"} 
                        size="small"
                        sx={rule.mode === 'select' ? styles.chip.warning : styles.chip.success}
                      />
                      {rule.useAllNodes && (
                        <Chip 
                          label="全部节点" 
                          size="small"
                          sx={styles.chip.primary}
                        />
                      )}
                    </Stack>
                    {!rule.useAllNodes && (
                      <Box sx={{ mb: 1 }}>
                        <Typography variant="body2" color="text.secondary" gutterBottom>
                          包含规则:
                        </Typography>
                        <Stack direction="row" spacing={0.5} flexWrap="wrap" useFlexGap>
                          {rule.includePatterns.map((pattern, index) => (
                            <Chip 
                              key={index}
                              label={pattern}
                              size="small"
                              sx={{ ...styles.chip.success, mt: 0.5 }}
                            />
                          ))}
                        </Stack>
                      </Box>
                    )}
                    {!rule.useAllNodes && rule.excludePatterns.length > 0 && (
                      <Box>
                        <Typography variant="body2" color="text.secondary" gutterBottom>
                          排除规则:
                        </Typography>
                        <Stack direction="row" spacing={0.5} flexWrap="wrap" useFlexGap>
                          {rule.excludePatterns.map((pattern, index) => (
                            <Chip 
                              key={index}
                              label={pattern}
                              size="small"
                              sx={{ ...styles.chip.error, mt: 0.5 }}
                            />
                          ))}
                        </Stack>
                      </Box>
                    )}
                  </CardContent>
                </Card>
              </motion.div>
            </Grid>
          ))}
        </Grid>
      </motion.div>

      <Dialog 
        open={openDialog} 
        onClose={handleCloseDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>
          {selectedRule ? '编辑规则' : '添加规则'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="规则名称"
                  value={editRule.name}
                  onChange={(e) => setEditRule({ ...editRule, name: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="规则类型"
                  value={editRule.type}
                  onChange={(e) => setEditRule({ ...editRule, type: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12}>
                <FormControl fullWidth size="small">
                  <InputLabel>节点选择模式</InputLabel>
                  <Select
                    value={editRule.mode}
                    label="节点选择模式"
                    onChange={(e) => setEditRule({ ...editRule, mode: e.target.value })}
                    sx={styles.textField}
                  >
                    <MenuItem value="select">手动选择</MenuItem>
                    <MenuItem value="urltest">自动测速</MenuItem>
                  </Select>
                  <FormHelperText>
                    {editRule.mode === 'select' ? '手动选择节点' : '自动选择可用和延迟较低的节点'}
                  </FormHelperText>
                </FormControl>
              </Grid>
              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={editRule.useAllNodes}
                      onChange={(e) => setEditRule({ ...editRule, useAllNodes: e.target.checked })}
                    />
                  }
                  label="使用全部节点"
                />
              </Grid>
              {!editRule.useAllNodes && (
                <>
                  <Grid item xs={12}>
                    <Typography variant="subtitle2" gutterBottom sx={{ mt: 1 }}>
                      节点匹配规则
                    </Typography>
                    <Stack spacing={2}>
                      <Box>
                        <Typography variant="body2" color="text.secondary" gutterBottom>
                          包含节点（白名单模式）
                        </Typography>
                        <TextField
                          fullWidth
                          multiline
                          rows={3}
                          placeholder="每行一个正则表达式，例如：^香港.*$"
                          value={editRule.includePatterns.join('\n')}
                          onChange={(e) => setEditRule({
                            ...editRule,
                            includePatterns: e.target.value.split('\n').filter(p => p.trim())
                          })}
                          size="small"
                          sx={styles.textField}
                        />
                      </Box>
                      <Box>
                        <Typography variant="body2" color="text.secondary" gutterBottom>
                          排除节点（黑名单模式）
                        </Typography>
                        <TextField
                          fullWidth
                          multiline
                          rows={3}
                          placeholder="每行一个正则表达式，例如：.*过期.*"
                          value={editRule.excludePatterns.join('\n')}
                          onChange={(e) => setEditRule({
                            ...editRule,
                            excludePatterns: e.target.value.split('\n').filter(p => p.trim())
                          })}
                          size="small"
                          sx={styles.textField}
                        />
                      </Box>
                    </Stack>
                  </Grid>
                  {editRule.mode === 'select' && (
                    <Grid item xs={12}>
                      <Typography variant="subtitle2" gutterBottom>
                        手动选择节点
                      </Typography>
                      <Box sx={{ maxHeight: 200, overflowY: 'auto', mt: 1 }}>
                        <Stack spacing={1}>
                          {editRule.nodeList.map((node) => (
                            <FormControlLabel
                              key={node.id}
                              control={
                                <Checkbox
                                  checked={editRule.selectedNodes.includes(node.id)}
                                  onChange={(e) => {
                                    const newSelectedNodes = e.target.checked
                                      ? [...editRule.selectedNodes, node.id]
                                      : editRule.selectedNodes.filter(id => id !== node.id);
                                    setEditRule({ ...editRule, selectedNodes: newSelectedNodes });
                                  }}
                                  size="small"
                                />
                              }
                              label={node.name}
                            />
                          ))}
                        </Stack>
                      </Box>
                    </Grid>
                  )}
                </>
              )}
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={handleCloseDialog} 
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button 
            variant="contained" 
            onClick={handleSave}
            disabled={loading}
            size="small"
            sx={styles.actionButton}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Rules;
